/**
 * ============================================================
 *  日本語教材 画像生成スクリプト v5
 *  対象: 第3課以降（第2課でも使用可）
 *
 *  第2課(v4)からの改善点:
 *
 *  [対策1] imageConfig フィールド名を固定
 *    gemini-2.5-flash-image の正しい REST payload:
 *      generationConfig.imageConfig.aspectRatio: "1:1"
 *    ※ imageGenerationConfig(旧 preview 用)は使わない
 *
 *  [対策2] モデル名を動作確認済みのものに固定
 *    "gemini-2.5-flash-image" — 第2課で実際に30枚生成済み
 *
 *  [対策3] タイムアウト対策 — 自動バッチ分割実行
 *    runAll() が JSON の件数を自動計算し、
 *    1バッチあたり MAX_BATCH_SIZE 件ずつ処理する。
 *    途中でタイムアウトしても次回 runAll() 実行時に
 *    未生成エントリだけを処理する「スキップ機能」付き。
 *
 *  [対策4] imageRef コピーの確実化
 *    参照元エントリの生成直後にインメモリの urlCache を更新。
 *    imageRef コピー時は urlCache から URL を取得するため
 *    JSON ファイルの imageUrl が null でも正しく動作する。
 *
 *  使い方:
 *    1. SETTINGS を設定する（API_KEY / FOLDER_ID / JSON_FILE_ID / SS_ID）
 *    2. testSingleImage() でテスト実行
 *    3. runAll() で全件実行（何度実行しても未生成分だけ処理する）
 *    4. 完了後に exportUrlsToJson() を実行
 * ============================================================
 */

// ===== 設定エリア（ここだけ編集する） =====
const SETTINGS = {
  API_KEY:         "AIzaSyBD_-7xrVnuPIH8-3oxNdSoTyBMYzwxPbA",        // ← Gemini API キー
  IMAGE_FOLDER_ID: "1oKjTevlw_drl9EajbnU7gd7u6ibY-2Nl",       // ← 画像保存先の Drive フォルダ ID
  JSON_FILE_ID:    "1CLx0OjdJW9twz2WS5FaLpS4BXgrX8xDm",          // ← image_prompts_lessonN.json の Drive ファイル ID
  SS_ID:           "1Rf6pQyA5Fw0R8CzQKvRGcnJpVSzyVbimm22BD-RmPGQ",        // ← ログ用スプレッドシート ID
  SS_SHEET_NAME:   "画像生成ログ",               // ← 課ごとに変更する（例: "第3課_画像生成ログ"）

  // 動作確認済みモデル（変更不要）
  // gemini-2.5-flash-image: 第2課で30枚生成済み・imageConfig + "1:1"形式で動作確認済み
  MODEL:           "gemini-2.5-flash-image",

  DELAY_MS:        4000,   // 生成間隔（ms）タイムアウトする場合は 2000 に下げる

  // 1バッチあたりの最大処理件数（GAS 6分制限対策）
  // 1件あたり約10秒として: 20件 × 10秒 = 200秒 ≒ 3.3分（余裕あり）
  MAX_BATCH_SIZE:  6,
};
// ==========================================


/* ============================================================
   【メイン】runAll() — これだけ実行すればよい
   ============================================================
   - JSON の全セクションを自動収集し順番に処理する
   - 生成順序: character_assets → special_grid_images
                → vocabulary_images → example_images
     （imageRef 参照元を必ず先に生成するための順序）
   - スキップ機能: スプレッドシートに既に ✅ 成功 の記録がある
     エントリは再生成しない（何度実行しても安全）
   - バッチ制限: MAX_BATCH_SIZE 件ずつ処理し、超えたら終了。
     次回実行時に続きから自動再開する。
   ============================================================ */
function runAll() {
  console.log("===== 画像生成スクリプト v5 開始 =====");
  console.log(`モデル: ${SETTINGS.MODEL}`);

  const imagePrompts = loadJsonFromDrive(SETTINGS.JSON_FILE_ID);
  if (!imagePrompts) { console.log("JSON の読み込みに失敗しました。"); return; }

  const sheet = getOrCreateSheet(SETTINGS.SS_ID, SETTINGS.SS_SHEET_NAME);
  initSheetHeader(sheet);

  // スプレッドシートから生成済みエントリの ID を取得
  const doneIds = getDoneIds(sheet);
  console.log(`生成済みエントリ数: ${doneIds.size}`);

  // 処理対象エントリを生成順序で収集
  // character_assets / special_grid_images を先にすることで
  // imageRef コピーが確実に動作する
  const allEntries = [
    ...(imagePrompts.character_assets    || []),
    ...(imagePrompts.special_grid_images || []),
    ...(imagePrompts.vocabulary_images   || []),
    ...(imagePrompts.example_images      || []),
  ];

  // 未生成エントリだけ抽出
  const pending = allEntries.filter(e => !doneIds.has(e.id) && e.skip !== true);
// skip: true のエントリは永久にスキップ（手動生成済み画像・再生成防止用）
  console.log(`未生成エントリ数: ${pending.length} / 全体: ${allEntries.length}`);

  if (pending.length === 0) {
    console.log("✅ 全エントリ生成済みです。exportUrlsToJson() を実行してください。");
    return;
  }

  // URL キャッシュ: 生成済み + 今回生成したものの URL を保持
  // imageRef コピー時に参照する
  const urlCache = buildUrlCache(sheet, allEntries);

  // バッチ処理
  const batch = pending.slice(0, SETTINGS.MAX_BATCH_SIZE);
  const remaining = pending.length - batch.length;

  console.log(`今回処理: ${batch.length} 件 / 残り: ${remaining} 件`);
  if (remaining > 0) {
    console.log(`⚠️ 残り ${remaining} 件は次回 runAll() で処理されます`);
  }

  let successCount = 0;
  let skipCount    = 0;
  let errorCount   = 0;

  for (const entry of batch) {
    const result = processEntry(entry, sheet, urlCache);
    if      (result === "success") successCount++;
    else if (result === "skip")    skipCount++;
    else                           errorCount++;
    Utilities.sleep(SETTINGS.DELAY_MS);
  }

  console.log(`===== バッチ完了 =====`);
  console.log(`成功: ${successCount} / スキップ(imageRef): ${skipCount} / エラー: ${errorCount}`);

  if (remaining > 0) {
    console.log(`残り ${remaining} 件 → もう一度 runAll() を実行してください`);
  } else {
    console.log("✅ 全件処理完了！exportUrlsToJson() を実行してください");
  }
}


/* ============================================================
   【サブ】1エントリを処理する
   戻り値: "success" / "skip" / "error"
   ============================================================ */
function processEntry(entry, sheet, urlCache) {
  console.log(`処理中: ${entry.id} / ${entry.filename || "(filename なし)"}`);

  // ── imageRef がある場合: 参照先の URL をコピー ──
  if (entry.imageRef) {
    const refUrl = urlCache[entry.imageRef];
    if (!refUrl) {
      console.log(`  ⚠️ imageRef 先の URL がキャッシュにありません: ${entry.imageRef}`);
      console.log(`  → ${entry.imageRef} がまだ生成されていない可能性があります`);
      logToSheet(sheet, {
        id:        entry.id,
        filename:  entry.filename || "",
        word:      entry.sentence || entry.description || "",
        size:      entry.size || "",
        status:    `⚠️ imageRef 先未生成: ${entry.imageRef}`,
        timestamp: new Date().toLocaleString("ja-JP"),
        prompt:    `imageRef: ${entry.imageRef}`,
      });
      return "error";
    }
    // URL をキャッシュに登録
    urlCache[entry.id] = refUrl;
    logToSheet(sheet, {
      id:        entry.id,
      filename:  entry.filename || "",
      word:      entry.sentence || entry.description || "",
      size:      entry.size || "",
      fileUrl:   refUrl,
      directUrl: refUrl,
      status:    `📋 imageRef コピー (${entry.imageRef})`,
      timestamp: new Date().toLocaleString("ja-JP"),
      prompt:    `imageRef: ${entry.imageRef}`,
    });
    console.log(`  📋 imageRef コピー完了: ${entry.id} → ${entry.imageRef}`);
    return "skip";
  }

  // ── 通常の生成処理 ──
  const prompt = entry.prompt;
  if (!prompt) {
    console.log(`  ⚠️ スキップ: prompt が見つかりません (${entry.id})`);
    logToSheet(sheet, {
      id:       entry.id,
      filename: entry.filename || "",
      word:     entry.word || entry.sentence || "",
      size:     entry.size || "",
      status:   "⚠️ スキップ (prompt なし)",
      timestamp: new Date().toLocaleString("ja-JP"),
    });
    return "error";
  }

  try {
    const result = generateWithGemini(prompt, entry.filename, entry.size);

    if (result.success) {
      // 生成成功 → URL をキャッシュに登録（後続の imageRef コピーで使用）
      urlCache[entry.id] = result.directUrl;
      logToSheet(sheet, {
        id:        entry.id,
        filename:  entry.filename,
        word:      entry.word || entry.sentence || entry.description || "",
        size:      entry.size,
        fileUrl:   result.fileUrl,
        directUrl: result.directUrl,
        status:    "✅ 成功",
        timestamp: new Date().toLocaleString("ja-JP"),
        prompt:    prompt.substring(0, 100) + "...",
      });
      console.log(`  ✅ 成功: ${entry.filename}`);
      return "success";
    } else {
      logToSheet(sheet, {
        id:        entry.id,
        filename:  entry.filename,
        word:      entry.word || entry.sentence || entry.description || "",
        size:      entry.size,
        status:    `❌ エラー: ${result.error}`,
        timestamp: new Date().toLocaleString("ja-JP"),
        prompt:    prompt.substring(0, 100) + "...",
      });
      console.log(`  ❌ エラー: ${entry.filename} → ${result.error}`);
      return "error";
    }
  } catch (e) {
    console.log(`  ❌ 例外: ${entry.id} → ${e.message}`);
    logToSheet(sheet, {
      id:        entry.id,
      filename:  entry.filename || "",
      word:      entry.word || entry.sentence || "",
      size:      entry.size || "",
      status:    `❌ 例外: ${e.message}`,
      timestamp: new Date().toLocaleString("ja-JP"),
    });
    return "error";
  }
}


/* ============================================================
   スプレッドシートから生成済み ID セットを取得
   ✅ 成功 / 📋 imageRef コピー の行を「完了」とみなす
   ============================================================ */
function getDoneIds(sheet) {
  const doneIds = new Set();
  if (sheet.getLastRow() <= 1) return doneIds;

  const data = sheet.getDataRange().getValues();
  for (let i = 1; i < data.length; i++) {
    const id     = data[i][0];
    const status = data[i][6];
    if (id && status && (status.startsWith("✅") || status.startsWith("📋"))) {
      doneIds.add(id);
    }
  }
  return doneIds;
}


/* ============================================================
   スプレッドシートから既存 URL を読み取り urlCache を構築
   新規生成した URL はその場で urlCache に追加する設計
   ============================================================ */
function buildUrlCache(sheet, allEntries) {
  const cache = {};

  // スプレッドシートの成功行から URL を取得
  if (sheet.getLastRow() > 1) {
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
      const id        = data[i][0];
      const directUrl = data[i][5];
      const status    = data[i][6];
      if (id && directUrl && (status.startsWith("✅") || status.startsWith("📋"))) {
        cache[id] = directUrl;
      }
    }
  }

  return cache;
}


/* ============================================================
   Gemini API で画像生成（動作確認済み設定）
   モデル: gemini-2.5-flash-image
   payload: generationConfig.imageConfig.aspectRatio
   第2課で30枚生成済み・この構造で動作確認済み
   ============================================================ */
function generateWithGemini(prompt, filename, aspectRatio) {
  const url = `https://generativelanguage.googleapis.com/v1beta/models/${SETTINGS.MODEL}:generateContent?key=${SETTINGS.API_KEY}`;

  // aspectRatio: "1:1" / "16:9" の文字列をそのまま渡す
  // imageConfig が正しいフィールド名（imageGenerationConfig は旧 preview 用・無効）
  const payload = {
    contents: [
      {
        parts: [{ text: prompt }]
      }
    ],
    generationConfig: {
      responseModalities: ["IMAGE", "TEXT"],
      imageConfig: {
        aspectRatio: aspectRatio,
      }
    }
  };

  const options = {
    method:             "post",
    contentType:        "application/json",
    payload:            JSON.stringify(payload),
    muteHttpExceptions: true,
  };

  const response = UrlFetchApp.fetch(url, options);
  const result   = JSON.parse(response.getContentText());

  if (result.error) return { success: false, error: result.error.message };

  const candidates = result.candidates;
  if (!candidates || candidates.length === 0) {
    return { success: false, error: "candidates が空です（安全フィルタ等）" };
  }

  const parts     = candidates[0].content.parts;
  const imagePart = parts.find(p => p.inlineData && p.inlineData.mimeType.startsWith("image/"));

  if (!imagePart) {
    const textPart = parts.find(p => p.text);
    return { success: false, error: textPart ? textPart.text : "画像パートが見つかりません" };
  }

  const base64Data = imagePart.inlineData.data;
  const mimeType   = imagePart.inlineData.mimeType || "image/png";
  const imageBlob  = Utilities.newBlob(
    Utilities.base64Decode(base64Data),
    mimeType,
    filename
  );

  return saveFileToDrive(imageBlob, filename);
}


/* ============================================================
   URL エクスポート — 生成完了後に実行する
   スプレッドシートの成功行を読み取り:
     1. コンソールに JSON 形式で出力
     2. "URLマッピング" シートに書き出す
   ============================================================ */
function exportUrlsToJson() {
  const sheet = getOrCreateSheet(SETTINGS.SS_ID, SETTINGS.SS_SHEET_NAME);
  const data  = sheet.getDataRange().getValues();

  const urlMap = {};
  for (let i = 1; i < data.length; i++) {
    const [id, , , , , directUrl, status] = data[i];
    if (id && directUrl && (status.startsWith("✅") || status.startsWith("📋"))) {
      urlMap[id] = directUrl;
    }
  }

  console.log("=== URLマッピング（image_prompts_lessonN.json の imageUrl に貼り付け用） ===");
  console.log(JSON.stringify(urlMap, null, 2));
  console.log(`成功件数: ${Object.keys(urlMap).length} 件`);

  // URLマッピングシートに書き出す
  const ss       = SpreadsheetApp.openById(SETTINGS.SS_ID);
  const mapName  = `URLマッピング_${SETTINGS.SS_SHEET_NAME.replace("_画像生成ログ", "")}`;
  let   mapSheet = ss.getSheetByName(mapName);
  if (!mapSheet) mapSheet = ss.insertSheet(mapName);
  mapSheet.clearContents();
  mapSheet.appendRow(["ID", "直接URL（imageUrl）", "取得日時"]);
  const now = new Date().toLocaleString("ja-JP");
  for (const [id, url] of Object.entries(urlMap)) {
    mapSheet.appendRow([id, url, now]);
  }

  console.log(`シート「${mapName}」に ${Object.keys(urlMap).length} 件を書き出しました`);
}


/* ============================================================
   テスト実行 — 1枚だけ生成して動作確認する
   ============================================================ */
function testSingleImage() {
  console.log("=== テスト実行（1枚）===");
  console.log(`モデル: ${SETTINGS.MODEL}`);

  const testEntry = {
    id:       "TEST_vocab_時計",
    filename: "TEST_vocab_時計_v5.png",
    word:     "時計（テスト）",
    size:     "1:1",
    prompt:   "Create a simple vocabulary card illustration. A single classic round analog wall clock, centered, flat vector style, clean black outlines, white background, no text, no numbers.",
  };

  const sheet = getOrCreateSheet(SETTINGS.SS_ID, SETTINGS.SS_SHEET_NAME);
  initSheetHeader(sheet);

  const result = processEntry(testEntry, sheet, {});
  console.log(`テスト結果: ${result}`);
  console.log("=== テスト完了 ===");
}


/* ============================================================
   個別 ID を指定して再生成する
   エラーになったエントリを単体で再試行する場合に使用
   ============================================================ */
function runRegenerateById() {
  const TARGET_ID = "ex_L01_05";   // ← 再生成したい ID に変更する

  console.log(`===== 個別再生成: ${TARGET_ID} =====`);

  const imagePrompts = loadJsonFromDrive(SETTINGS.JSON_FILE_ID);
  if (!imagePrompts) { console.log("JSON の読み込みに失敗しました。"); return; }

  const allEntries = [
    ...(imagePrompts.character_assets    || []),
    ...(imagePrompts.special_grid_images || []),
    ...(imagePrompts.vocabulary_images   || []),
    ...(imagePrompts.example_images      || []),
  ];

  const entry = allEntries.find(e => e.id === TARGET_ID);
  if (!entry) {
    console.log(`ID "${TARGET_ID}" が見つかりませんでした`);
    allEntries.forEach(e => console.log(` - ${e.id}`));
    return;
  }

  const sheet = getOrCreateSheet(SETTINGS.SS_ID, SETTINGS.SS_SHEET_NAME);
  initSheetHeader(sheet);

  // 再生成時も urlCache を構築（imageRef コピーエントリの再生成に対応）
  const urlCache = buildUrlCache(sheet, allEntries);
  processEntry(entry, sheet, urlCache);

  console.log(`===== 個別再生成完了: ${entry.filename} =====`);
}


/* ============================================================
   Drive にファイルを保存して URL を返す
   ============================================================ */
function saveFileToDrive(imageBlob, filename) {
  try {
    const folder    = DriveApp.getFolderById(SETTINGS.IMAGE_FOLDER_ID);
    const savedFile = folder.createFile(imageBlob);
    savedFile.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);
    const fileId = savedFile.getId();
    return {
      success:   true,
      fileUrl:   savedFile.getUrl(),
      directUrl: `https://drive.google.com/uc?id=${fileId}`,
      fileId,
    };
  } catch (e) {
    return { success: false, error: `Drive 保存エラー: ${e.message}` };
  }
}


/* ============================================================
   Drive から JSON ファイルを読み込む
   ============================================================ */
function loadJsonFromDrive(fileId) {
  try {
    const file = DriveApp.getFileById(fileId);
    return JSON.parse(file.getBlob().getDataAsString("utf-8"));
  } catch (e) {
    console.log(`JSON 読み込みエラー: ${e.message}`);
    return null;
  }
}


/* ============================================================
   スプレッドシートの取得・作成
   ============================================================ */
function getOrCreateSheet(ssId, sheetName) {
  const ss    = SpreadsheetApp.openById(ssId);
  let   sheet = ss.getSheetByName(sheetName);
  if (!sheet) {
    sheet = ss.insertSheet(sheetName);
    console.log(`シート「${sheetName}」を新規作成しました`);
  }
  return sheet;
}

function initSheetHeader(sheet) {
  if (sheet.getLastRow() > 0) return;
  const headers = [
    "ID", "ファイル名", "語彙／例文", "サイズ",
    "DriveURL（開く）", "直接URL（img src 用）",
    "ステータス", "生成日時", "プロンプト（先頭 100 文字）",
  ];
  sheet.appendRow(headers);
  const r = sheet.getRange(1, 1, 1, headers.length);
  r.setFontWeight("bold");
  r.setBackground("#EAF4FF");
  sheet.setFrozenRows(1);
  sheet.setColumnWidth(5, 250);
  sheet.setColumnWidth(6, 300);
  sheet.setColumnWidth(9, 400);
}

function logToSheet(sheet, data) {
  sheet.appendRow([
    data.id        || "",
    data.filename  || "",
    data.word      || "",
    data.size      || "",
    data.fileUrl   || "",
    data.directUrl || "",
    data.status    || "",
    data.timestamp || "",
    data.prompt    || "",
  ]);
}

const REGISTER_SETTINGS = {
  IMAGE_FOLDER_ID: SETTINGS.IMAGE_FOLDER_ID,
  JSON_FILE_ID:    SETTINGS.JSON_FILE_ID,
  SS_ID:           SETTINGS.SS_ID,
  SS_SHEET_NAME:   "手動登録ログ",
  overwrite:       false,  // true にすると既存 imageUrl を上書き
};

function registerManualImages() {
  console.log("===== 手動生成画像の登録開始 =====");

  const imagePrompts = loadJsonFromDrive(REGISTER_SETTINGS.JSON_FILE_ID);
  if (!imagePrompts) {
    console.log("❌ JSON の読み込みに失敗しました。JSON_FILE_ID を確認してください。");
    return;
  }

  const folder = DriveApp.getFolderById(REGISTER_SETTINGS.IMAGE_FOLDER_ID);
  const files  = folder.getFiles();

  const fileMap = {};
  while (files.hasNext()) {
    const file     = files.next();
    const fileName = file.getName();
    const id = fileName.replace(/\.(png|jpg|jpeg|webp)$/i, "");
    fileMap[id] = {
      fileId:    file.getId(),
      directUrl: `https://drive.google.com/uc?id=${file.getId()}`,
      fileName:  fileName,
    };
  }
  console.log(`Drive フォルダ内のファイル数: ${Object.keys(fileMap).length}`);

  const allEntries = [
    ...(imagePrompts.character_assets    || []),
    ...(imagePrompts.special_grid_images || []),
    ...(imagePrompts.vocabulary_images   || []),
    ...(imagePrompts.example_images      || []),
  ];

  const sheet = getOrCreateSheet(REGISTER_SETTINGS.SS_ID, REGISTER_SETTINGS.SS_SHEET_NAME);
  if (sheet.getLastRow() === 0) {
    sheet.appendRow(["ID", "ファイル名", "Drive URL", "ステータス", "登録日時"]);
    const r = sheet.getRange(1, 1, 1, 5);
    r.setFontWeight("bold");
    r.setBackground("#EAF4FF");
    sheet.setFrozenRows(1);
  }

  let registeredCount = 0;
  let skippedCount    = 0;
  let notFoundCount   = 0;
  const now = new Date().toLocaleString("ja-JP");

  for (const entry of allEntries) {
    const id    = entry.id;
    const match = fileMap[id];

    if (!match) {
      notFoundCount++;
      continue;
    }

    if (entry.imageUrl && !REGISTER_SETTINGS.overwrite) {
      console.log(`  ⏭️ スキップ（既登録）: ${id}`);
      sheet.appendRow([id, match.fileName, match.directUrl, "⏭️ スキップ（既登録）", now]);
      skippedCount++;
      continue;
    }

    entry.imageUrl = match.directUrl;
    entry.skip     = true;
    registeredCount++;

    console.log(`  ✅ 登録: ${id} → ${match.directUrl}`);
    sheet.appendRow([id, match.fileName, match.directUrl, "✅ 登録", now]);
  }

  if (registeredCount > 0) {
    const file    = DriveApp.getFileById(REGISTER_SETTINGS.JSON_FILE_ID);
    const updated = JSON.stringify(imagePrompts, null, 2);
    file.setContent(updated);
    console.log(`✅ JSON を更新しました（${registeredCount} 件登録）`);
  } else {
    console.log("ℹ️ 新規登録対象なし（JSON は更新しませんでした）");
  }

  console.log("===== 登録完了 =====");
  console.log(`登録: ${registeredCount} 件 / スキップ（既登録）: ${skippedCount} 件 / Drive に未存在: ${notFoundCount} 件`);
}
